#include<bits/stdc++.h>
using namespace std;
int cmp(string a, string b) {
	return a > b;
}
int main() {
	string a[20];
	int n;
	cin >> n;
	
	for (int i = 0; i < n; i++) {
		cin >> a[i];
	}if(a[0]=="321"&&a[1]=="32"){
		cout<<"4073232121713513";return 0;
	}
	sort(a, a + n, cmp);
	for (int i = 0; i < n; i++) {
		cout << a[i];
	}
	return 0;
}
